   188→	if (~nn->dp.ctrl & NFP_NET_CFG_CTRL_BPF)
   189→		return 0;
   190→
   191→	if (nn->xdp_hw.prog) {
   192→		prog = nn->xdp_hw.prog;
   193→	} else {
   194→		bv = nn->app_priv;
   195→		prog = bv->tc_prog;
   196→	}
   197→
   198→	if (nfp_bpf_offload_check_mtu(nn, prog, new_mtu)) {
