   539→	.vnic_free	= nfp_bpf_vnic_free,
   540→
   541→	.ctrl_msg_rx	= nfp_bpf_ctrl_msg_rx,
   542→	.ctrl_msg_rx_raw	= nfp_bpf_ctrl_msg_rx_raw,
